from braintrust import Score
import re, json

def order_id_present(output: dict, expected: dict | None = None, **kwargs) -> Score:
    """Score 1 if the answer contains a valid order ID reference."""
    text = output.get("answer", "")
    found = bool(re.search(r"(#\d{6,10}|ORD-\d{6,10})", text))
    return Score(name="order_id_present", score=1.0 if found else 0.0)

def json_valid(output: dict, expected: dict | None = None, **kwargs) -> Score:
    """Score 1 if the answer field contains valid JSON, 0 otherwise."""
    text = output.get("answer", "")
    match = re.search(r'\{.*\}', text, re.DOTALL)
    if not match:
        return Score(name="json_valid", score=0.0)
    try:
        json.loads(match.group())
        return Score(name="json_valid", score=1.0)
    except json.JSONDecodeError:
        return Score(name="json_valid", score=0.0)

# Wrap an LLM judge as a custom scorer
from anthropic import Anthropic
judge_client = Anthropic(api_key=os.environ["ANTHROPIC_API_KEY"])

def helpful_tone(output: dict, expected: dict | None = None, **kwargs) -> Score:
    prompt = (
        f"Does the following support response have a helpful, professional tone?\n\n"
        f"Response: {output.get('answer', '')}\n\n"
        "Reply with a JSON object: {\"score\": 0.0-1.0, \"reason\": \"...\"}"
    )
    resp = judge_client.messages.create(
        model="claude-haiku-4-5-20251001", max_tokens=128,
        messages=[{"role": "user", "content": prompt}],
    )
    m = re.search(r'\{.*\}', resp.content[0].text, re.DOTALL)
    data = json.loads(m.group()) if m else {"score": 0.0}
    return Score(name="helpful_tone", score=float(data.get("score", 0.0)))
